+                    write_to_slave_and_read_master(&mut master, &slave_dup, ALT_SCREEN_ENTER);
+                assert!(
+                    output
+                        .windows(ALT_SCREEN_ENTER.len())
+                        .any(|w| w == ALT_SCREEN_ENTER),
