+                // Leave alt-screen.
+                let output =
+                    write_to_slave_and_read_master(&mut master, &slave_dup, ALT_SCREEN_LEAVE);
+                assert!(
+                    output
+                        .windows(ALT_SCREEN_LEAVE.len())
+                        .any(|w| w == ALT_SCREEN_LEAVE),
+                    "alt-screen leave should pass through PTY"
+                );
+            }
+        }
